const item = $input.first().json;

// Extraer remitente
let fromString = '';
if (typeof item.from === 'string') fromString = item.from;
else if (item.from?.text) fromString = item.from.text;
else if (item.from?.value?.[0]) {
  const v = item.from.value[0];
  fromString = `${v.name || ''} <${v.address || ''}>`;
} else fromString = JSON.stringify(item.from);

const subject = item.subject || '';

// Usar el contenido HTML del correo para obtener más texto
let htmlContent = item.html || '';
let bodyText = htmlContent
  .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
  .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

if (bodyText.length < 200) {
  bodyText = item.text || '';
}

const maxChars = 8000;
if (bodyText.length > maxChars) {
  bodyText = bodyText.substring(0, maxChars);
}

bodyText = bodyText.replace(/-{5,}/g, '').replace(/\n{3,}/g, '\n\n');

const prompt = `Eres un asistente de reclutamiento. Extrae del siguiente correo TODAS las ofertas de trabajo (máximo 5). Para cada oferta, devuelve un JSON con esta estructura EXACTA:
{
  "ofertas": [
    {
      "titulo": "",
      "empresa": "",
      "ubicacion": "",
      "sector": "",
      "tamano": "",
      "requisitos_tecnicos": [],
      "anos_experiencia": null,
      "responsabilidades": [],
      "herramientas": [],
      "url_oferta": null,
      "resumen": "",
      "experiencia_requerida": null,
      "modalidad": null,
      "idioma_requerido": null,
      "nivel_idioma": null
    }
  ]
}
- sector: industria de la empresa (ej. "Banca", "Tecnología", etc.). Si no se menciona, pon null.
- tamano: número de empleados (ej. "De 1.001 a 5.000 empleados", "Menos de 100", etc.). Si no se menciona, pon null.
- experiencia_requerida: años de experiencia solicitados (número, ej. 3). Si no se menciona, pon null.
- modalidad: "remoto", "presencial" o "híbrido". Si no se menciona, pon null.
- idioma_requerido: idioma solicitado (ej. "inglés"). Si no se menciona, pon null.
- nivel_idioma: nivel requerido (ej. "básico", "intermedio", "avanzado", "nativo"). Si no se menciona, pon null.
Si no hay ofertas, devuelve {"ofertas": []}. No añadas texto adicional fuera del JSON.

**IMPORTANTE**: Si el correo NO incluye una lista explícita de requisitos técnicos, INFIERE hasta 5 habilidades técnicas probables para el puesto basándote en su título y sector. USA ESTAS HABILIDADES INFERIDAS ÚNICAMENTE para completar el campo 'requisitos_tecnicos' del JSON interno y así mejorar el cálculo de compatibilidad. NO INCLUYAS estas habilidades inferidas en el campo 'resumen' ni en ningún otro lugar que pueda ser interpretado como un requisito oficial de la oferta.

Correo:
De: ${fromString}
Asunto: ${subject}
Cuerpo: ${bodyText}`;

const requestBody = {
  model: "llama-3.3-70b-versatile",
  messages: [
    {
      role: "user",
      content: prompt
    }
  ],
  temperature: 0,
  max_tokens: 4000
};

return { body: JSON.stringify(requestBody) };

// Obtener la respuesta de Gemini desde el nodo HTTP Request
const response = $input.first().json;

// Extraer el texto de la respuesta (puede venir en diferentes formatos)
let text = '';
try {
  text = response.candidates?.[0]?.content?.parts?.[0]?.text || '';
} catch (e) {
  text = '';
}

// Si no hay texto, intentar con otras estructuras (por si la API cambia)
if (!text && response.choices?.[0]?.message?.content) {
  text = response.choices[0].message.content; // Formato alternativo
}

// Limpiar el texto: eliminar markdown, espacios, etc.
let cleanText = text.trim();

// Si la respuesta viene envuelta en triple backticks json ... ```, extraer solo el JSON
const jsonMatch = cleanText.match(/```json\s*([\s\S]*?)\s*```/);
if (jsonMatch) {
  cleanText = jsonMatch[1];
} else {
  // Si no tiene triple backticks, buscar un objeto JSON directamente
  const objMatch = cleanText.match(/\{[\s\S]*\}/);
  if (objMatch) {
    cleanText = objMatch[0];
  }
}

// Intentar parsear el JSON
let ofertas = { ofertas: [] };
try {
  const parsed = JSON.parse(cleanText);
  // Asegurar que tenga la propiedad "ofertas"
  if (parsed.ofertas && Array.isArray(parsed.ofertas)) {
    ofertas = parsed;
  } else if (Array.isArray(parsed)) {
    // Si devolvió directamente un array
    ofertas = { ofertas: parsed };
  } else if (parsed.titulo) {
    // Si devolvió una sola oferta (no array)
    ofertas = { ofertas: [parsed] };
  }
} catch (e) {
  console.error('Error parsing JSON:', e.message);
  // Si falla, devolver array vacío
  ofertas = { ofertas: [] };
}

// Asegurar que cada oferta tenga todos los campos necesarios (para evitar errores posteriores)
const camposRequeridos = ['titulo', 'empresa', 'ubicacion', 'requisitos_tecnicos', 'anos_experiencia', 'responsabilidades', 'herramientas', 'url_oferta', 'resumen'];
ofertas.ofertas = ofertas.ofertas.map(oferta => {
  const completa = { ...oferta };
  for (const campo of camposRequeridos) {
    if (completa[campo] === undefined) {
      completa[campo] = (campo === 'requisitos_tecnicos' || campo === 'responsabilidades' || campo === 'herramientas') ? [] : null;
    }
  }
  return completa;
});

// Devolver solo el objeto con el array de ofertas
return ofertas;

// Obtener todos los items de entrada (cada uno es { oferta, perfil })
const items = $input.all();
const resultados = [];

// Función para normalizar texto (quita tildes, minúsculas, caracteres especiales)
function normalizar(texto) {
  return texto
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase()
    .replace(/[^a-z0-9\s]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

// Calcular compatibilidad técnica usando el array de habilidades del perfil
function calcularCompatibilidadTecnica(oferta, perfil) {
  const habilidadesPerfil = (perfil.habilidades_tecnicas || []).map(h => normalizar(h));
  const requisitosOferta = (oferta.requisitos_tecnicos || [])
    .map(r => normalizar(r))
    .filter(r => r.length > 0);

  if (requisitosOferta.length === 0) {
    return { puntaje: 50, coincidencias: [], faltantes: [] };
  }

  let puntaje = 50;
  const coincidencias = [];
  const faltantes = [];

  for (const req of requisitosOferta) {
    let coincide = false;

    // 1. Coincidencia exacta o como subcadena
    coincide = habilidadesPerfil.some(h => h.includes(req) || req.includes(h));

    // 2. Lógica semántica para casos generales
    if (!coincide) {
      // "analisis de datos" puede coincidir con "análisis de datos", "data", "analista"
      if (req.includes('analisis') && req.includes('datos')) {
        coincide = habilidadesPerfil.some(h => h.includes('analisis') || h.includes('data') || h.includes('analista'));
      }
      // "herramientas de visualizacion" puede coincidir con "visualizacion", "power bi", "matplotlib", "seaborn"
      else if (req.includes('herramientas') && req.includes('visualizacion')) {
        coincide = habilidadesPerfil.some(h => h.includes('visualizacion') || h.includes('power bi') || h.includes('matplotlib') || h.includes('seaborn'));
      }
      // --- NUEVAS REGLAS SEMÁNTICAS (Corrección de falsos negativos) ---
      // "lenguajes de programacion" conecta con Python, SQL, JavaScript, etc.
      else if (req.includes('lenguajes') && req.includes('programacion')) {
        coincide = habilidadesPerfil.some(h => h.includes('python') || h.includes('sql') || h.includes('javascript') || h.includes('java') || h.includes('c#') || h.includes('c++') || h.includes('typescript'));
      }
      // "bases de datos" conecta con SQL, MySQL, Oracle, PostgreSQL, etc.
      else if (req.includes('bases') && req.includes('datos')) {
        coincide = habilidadesPerfil.some(h => h.includes('sql') || h.includes('mysql') || h.includes('oracle') || h.includes('postgresql') || h.includes('mongodb'));
      }
      // --- FIN NUEVAS REGLAS ---
    }

    if (coincide) {
      puntaje += 15;
      coincidencias.push(req);
    } else {
      puntaje -= 5;
      faltantes.push(req);
    }
  }

  puntaje = Math.min(100, Math.max(0, puntaje));
  return { puntaje, coincidencias, faltantes };
}

// Calcular score financiero (con la mejora de incluir "finanzas")
function calcularScoreFinanciero(oferta) {
  let score = 0;
  const sector = (oferta.sector || '').toLowerCase();
  const tamano = (oferta.tamano || '').toLowerCase();

  // Incluir "finanzas", "banco" y similares
  if (sector.includes('banca') || sector.includes('financiero') || sector.includes('finanzas') || sector.includes('banco')) {
    score += 30;
  } else if (sector.includes('tecnología') || sector.includes('consultoría') || sector.includes('ti')) {
    score += 20;
  } else if (sector.includes('telecomunicaciones') || sector.includes('datos')) {
    score += 10;
  }

  if (tamano.includes('1001') || tamano.includes('5000') || tamano.includes('10001')) score += 25;
  else if (tamano.includes('201') || tamano.includes('500') || tamano.includes('1000')) score += 15;
  else if (tamano.includes('menos de') || tamano.includes('1 a') || tamano.includes('pequeña')) score += 5;

  const esEstrategica = score >= 25;
  return { scoreFinanciero: score, esEstrategica };
}

// Procesar cada item
for (const item of items) {
  const oferta = item.json.oferta;
  const perfil = item.json.perfil;

  if (!oferta || !perfil) continue;

  const { puntaje, coincidencias, faltantes } = calcularCompatibilidadTecnica(oferta, perfil);
  const { scoreFinanciero, esEstrategica } = calcularScoreFinanciero(oferta);
  const puntajeTotal = Math.min(100, (puntaje * 0.7) + (scoreFinanciero * 0.3));

  const ofertaEnriquecida = {
    ...oferta,
    puntaje: puntaje,
    puntajeTecnico: puntaje,
    scoreFinanciero,
    esEstrategica,
    puntajeTotal,
    coincidencias,
    faltantes,
    requisitos_tecnicos: oferta.requisitos_tecnicos || [],
    // --- NUEVOS CAMPOS (sin afectar puntaje) ---
    experiencia_requerida: oferta.experiencia_requerida || null,
    modalidad: oferta.modalidad || null,
    idioma_requerido: oferta.idioma_requerido || null,
    nivel_idioma: oferta.nivel_idioma || null
    // --- FIN NUEVOS CAMPOS ---
  };

  resultados.push({
    oferta: ofertaEnriquecida,
    perfil: perfil,
    puntajeTotal: puntajeTotal
  });
}

// Si no hay resultados, devolver array vacío
if (resultados.length === 0) {
  return [];
}

return resultados;

// Obtener todos los items de entrada
const items = $input.all();
if (items.length === 0) return [];

// --- Función para ordenar viñetas por relevancia ---
